dslRule:
/*!id: jdt.internal.jls.jdk13.to.firstsupported*/
/*!description: Replaces the internal JDT constant ClassFileConstants.JDK1_3 with CompilerOptions.getFirstSupportedJdkLevel() to standardize baseline JLS version determination.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
org.eclipse.jdt.internal.compiler.classfmt.ClassFileConstants.JDK1_3
=> org.eclipse.jdt.internal.compiler.impl.CompilerOptions.getFirstSupportedJdkLevel()
;;

/*!id: jdt.internal.jls.jdk18.to.firstsupported*/
/*!description: Replaces the internal JDT constant ClassFileConstants.JDK1_8 with CompilerOptions.getFirstSupportedJdkLevel() to standardize baseline JLS version determination.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
org.eclipse.jdt.internal.compiler.classfmt.ClassFileConstants.JDK1_8
=> org.eclipse.jdt.internal.compiler.impl.CompilerOptions.getFirstSupportedJdkLevel()
;;

dslRuleAfterChange:
/* Hypothetical DSL syntax for structural replacement */
@id: jdt.internal.recorddeclaration.simplify-loop
@severity: info
@minJavaVersion: 16

RecordComponent[] $recComps = $typeDeclaration.recordComponents;
if ($recComps != null) {
    for (RecordComponent $recComp : $recComps) {
        $recordDeclaration.recordComponents().add(convert($recComp));
    }
}
=>
for (RecordComponent $component : $typeDeclaration.recordComponents) {
    $recordDeclaration.recordComponents().add(convert($component));
}
;;
